std::vector<ProductImages> Products::getImages(const DbClientPtr &clientPtr) const {
    static const std::string sql = "select * from product_images where product_id = $1";
    Result r(nullptr);
    {
        auto binder = *clientPtr << sql;
        binder << *id_ << Mode::Blocking >>
            [&r](const Result &result) { r = result; };
        binder.exec();
    }
    std::vector<ProductImages> ret;
    ret.reserve(r.size());
    for (auto const &row : r)
    {
        ret.emplace_back(ProductImages(row));
    }
    return ret;
}

void Products::getImages(const DbClientPtr &clientPtr,
                         const std::function<void(std::vector<ProductImages>)> &rcb,
                         const ExceptionCallback &ecb) const
{
    static const std::string sql = "select * from product_images where product_id = $1";
    *clientPtr << sql
               << *id_
               >> [rcb = std::move(rcb)](const Result &r){
                   std::vector<ProductImages> ret;
                   ret.reserve(r.size());
                   for (auto const &row : r)
                   {
                       ret.emplace_back(ProductImages(row));
                   }
                   rcb(ret);
               }
               >> ecb;
}
